const leads = $('Fetch Uncontacted Leads').all().map(i => i.json);
const alertHistoryRaw = $('Fetch Alert History').all().map(i => i.json);

// Handle case where lead_alerts table doesn't exist (alertHistory may be error)
const alertHistory = Array.isArray(alertHistoryRaw) ? alertHistoryRaw.filter(a => a.lead_id && a.alert_type) : [];

// Build set of already-alerted: "lead_id|alert_type"
const alerted = new Set();
for (const a of alertHistory) {
  alerted.add(`${a.lead_id}|${a.alert_type}`);
}

// Check business hours (CT = America/Chicago)
const now = new Date();
const ctHour = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' })).getHours();
if (ctHour < 8 || ctHour >= 21) return []; // Outside business hours

const results = [];
for (const lead of leads) {
  const ageMs = Date.now() - new Date(lead.created_at).getTime();
  const ageHours = ageMs / (1000 * 60 * 60);

  let alertLevel = null;
  let severity = '';
  let emoji = '';

  if (ageHours >= 8) {
    alertLevel = 'speed_to_lead_8h';
    severity = 'CRITICAL';
    emoji = '\ud83d\udea8\ud83d\udea8\ud83d\udea8';
  } else if (ageHours >= 4) {
    alertLevel = 'speed_to_lead_4h';
    severity = 'WARNING';
    emoji = '\u26a0\ufe0f\u26a0\ufe0f';
  } else if (ageHours >= 2) {
    alertLevel = 'speed_to_lead_2h';
    severity = 'ALERT';
    emoji = '\u23f0';
  }

  if (!alertLevel) continue;
  if (alerted.has(`${lead.id}|${alertLevel}`)) continue;

  const name = `${lead.first_name || ''} ${lead.last_name || ''}`.trim() || 'Unknown';
  const phone = lead.phone || 'No phone';
  const service = lead.service || 'Not specified';
  const hoursAgo = Math.round(ageHours * 10) / 10;
  const tierEmoji = (lead.lead_tier === 'hot') ? '\ud83d\udd25' : (lead.lead_tier === 'warm') ? '\ud83d\udfe1' : '\ud83d\udd35';

  const msg = `${emoji} SPEED TO LEAD ${severity}\n\n` +
    `Lead waiting ${hoursAgo} hours!\n\n` +
    `\ud83d\udc64 ${name}\n` +
    `\ud83d\udcf1 ${phone}\n` +
    `\ud83d\udd27 ${service}\n` +
    `${tierEmoji} Score: ${lead.lead_score || 0} (${lead.lead_tier || 'unknown'})\n\n` +
    `\ud83d\udcde Call NOW: tel:${(phone || '').replace(/[^+\d]/g, '')}`;

  results.push({
    json: {
      lead_id: lead.id,
      alert_type: alertLevel,
      message: msg,
      severity,
      hours_waiting: hoursAgo
    }
  });
}
return results;
